INSERT INTO "public"."recruitment_services" ("id", "link", "title", "title_desc", "title_cta", "title_img", "title_img_alt", "heading_1", "heading_1_desc", "heading_2", "heading_2_desc", "heading_2_list", "heading_3", "heading_3_desc", "heading_3_list", "heading_4", "heading_4_desc", "heading_4_list", "cta", "heading_5", "heading_5_desc", "created_at", "meta_title", "meta_desc") VALUES
	(2, 'bulk-hiring', 'Bulk Hiring', 'Big growth needs bold hiring. RaremindsΓÇÖ Bulk Hiring Services bring you skilled talent at scaleΓÇöfast, consistent, and ready to drive your business forward.', 'Book a Call', 'https://itvhjkgfafikpqmuunlh.supabase.co/storage/v1/object/public/images/Corporate/Recruitment/service/Bulk-hiring.webp', 'Business professionals collaborating over hiring, representing diversity, and high-volume recruitment.', 'Scale Fast, Hire Smart: Rareminds Bulk Hiring Services', '["When your business is scaling rapidly, getting the right talent at the right time requires slightly different recruitment procedures. Bulk hiring isn''t only about volume, itΓÇÖs also about consistency, quality, and speed.", "At Rareminds, we specialize in end-to-end bulk hiring solutions that help organizations meet aggressive talent requirements without compromising hiring standards."]', 'What Does Our Bulk Hiring Services Deliver?', 'Our high-volume recruitment strategies are built to handle the complexity and urgency of mass hiring projects while keeping candidate quality, cost efficiency, and operational alignment at the forefront.', '[{"t_1": "Talent Delivery and", "t_2": "Process Management", "points": ["Recruitment for 50 to 1000+ positions across locations and functions.", "Customized bulk hiring drives for sectors like Pharma and Healthcare, IT, Engineering, NBFC, BFSI, retail, manufacturing, logistics, and Real estate.", "Efficient coordination of walk-ins, job fairs, campus drives, and virtual hiring events.", "EndΓÇætoΓÇæend support: job ads and channel planning, centralized screening/interview coordination, documentation and background verifications, realΓÇætime reporting and analytics."]}, {"t_1": "Speed", "t_2": "hiring", "points": ["Streamlined sourcing, screening, and shortlisting processes to deliver results within defined timelines.", "AI-based applicant tracking and candidate filtering.", "Trained hiring teams deployed to accelerate screening and onboarding.", "Targeted messaging and campaigns to attract large candidate pools quickly."]}, {"t_1": "Enhanced", "t_2": "Candidate Experience", "points": ["Clear communication at every touchpoint.", "Branded hiring experiences that build trust and engagement.", "Pre-hire orientation, onboarding assistance, and first-week integration.", "Feedback collection and experience monitoring at volume."]}]', 'Bulk Hiring Engagement Models', 'We offer flexible models tailored to your scale, sector, and speed:', '[{"desc": "Full ownership of your mass hiring goals, from sourcing to onboarding, is executed by our dedicated bulk hiring teams.", "icon": "", "title": "Turnkey Bulk Hiring Solutions"}, {"desc": "End-to-end management of walk-in drives, job fairs, campus recruitment, and multi-location interview events.", "icon": "", "title": "Event-Based Hiring Support"}, {"desc": "Deploy our trained recruiters to your site to manage footfall, pre-screen candidates, and conduct initial assessments during mass hiring phases.", "icon": "", "title": "Recruiter on Ground (ROG)"}, {"desc": "High-impact, tech-driven sourcing campaigns using job portals, social media, WhatsApp automation, and SMS outreach to drive candidates.", "icon": "", "title": "Digital Bulk Hiring Campaigns"}]', 'Our Bulk Hiring Approach', 'We follow a proven 4-step strategy for seamless high-volume hiring:', '[{"title": "Planning and Demand Forecasting", "points": ["Understand hiring goals, job roles, locations, and timelines", "Workforce segmentation and hiring strategy design", "Sourcing channel mapping and volume estimation"]}, {"title": "Sourcing and Outreach", "points": ["Mass reach through digital and offline channels", "Targeted sourcing for entry-level, mid-level, and skilled roles", "Screening questions and filters built for speed and accuracy"]}, {"title": "Selection and Coordination", "points": ["Rapid pre-screening via telephonic/video interviews", "Centralized documentation and offer management", "Daily reporting and recruiter accountability"]}, {"title": "Onboarding and Fulfilment", "points": ["Verification support and joining follow-up", "Attrition buffer planning and replacement strategies", "Post-joining engagement to reduce early dropouts"]}]', 'Begin the Journey', 'Ready to Scale Hiring Without the Hassle?', 'Whether you''re launching a new unit or managing a hiring spike, RaremindsΓÇÖ Bulk Hiring Services deliver speed, accuracy, and retention without breaking your budget. LetΓÇÖs build your next high-performing team. Talk to us today and hire smarter, faster.', '2025-05-28 07:11:39.391489', 'Bulk Hiring Services | High-Volume Recruitment Experts', 'RaremindsΓÇÖ Bulk Hiring Services deliver skilled talent at scaleΓÇöfast, consistent, and industry-ready. 1000+ hires. 10+ sectors. End-to-end support.'),
	(5, 'project-based-hiring', 'Project-Based Hiring', 'Talent on your terms, when it counts. RaremindsΓÇÖ Project-Based Hiring delivers agile experts ready to power your projectsΓÇöno strings attached.', 'Book a Call', 'https://itvhjkgfafikpqmuunlh.supabase.co/storage/v1/object/public/images/Corporate/Recruitment/service/Project-Based.webp', 'Illustration showing recruiter at laptop screening resumes and steps of sourcing, interviewing, and onboarding represented with icons and flow arrows in vibrant colors.', 'On-Demand Talent, Just When You Need It: Rareminds Project-Based Hiring Solutions', '["Some business goals donΓÇÖt wait for headcount approvals. When projects move fast, you need talent ready to hit the ground running. Rareminds offers agile, project-specific hiring solutions that scale with your deliverables, not your payroll."]', 'What Does Our Project-Based Hiring Services Deliver?', 'From product launches to short-term rollouts, we provide domain-specific, contract-ready talent to meet your project timelines, budgets, and compliance needs.', '[{"t_1": "Role-Based", "t_2": "Precision Hiring", "points": ["Talent acquisition based on functional, technical, and domain-specific needs", "Pre-vetted candidates with proven project experience", "Hiring across IT, pharma, BFSI, FMCG, engineering, and operations", "Flexible durations: 3-month, 6-month, or milestone-based contracts"]}, {"t_1": "Agility Without,", "t_2": "Compromising Quality", "points": ["Quick TAT through pre-built talent pipelines and talent clouds", "Project-focused screening: technical assessments, case-based tasks", "Dedicated recruiters assigned per project"]}, {"t_1": "End-to-End Compliance", "t_2": "and Cost Control", "points": ["Contract management, payroll integration and compliance handling", "Onboarding, documentation, and background checks handling", "Transparent cost structures and time tracking"]}]', 'Project Hiring Engagement Models', 'Choose from scalable models based on your project scope, complexity, and delivery window:', '[{"desc": "Deploy candidates on 3ΓÇô12 month contracts specific to your project duration and budget.", "icon": "", "title": "Fixed-Term Staffing"}, {"desc": "Source talent in sync with each project phaseΓÇödesign, build, rollout, or post-go-live support.", "icon": "", "title": "Milestone-Based Talent Sourcing"}, {"desc": "Create a ready-to-deploy bench of pre-screened candidates for upcoming or seasonal project cycles.", "icon": "", "title": "Project Roster Building"}, {"desc": "Test talent in a project context before converting them to full-time based on performance and fit.", "icon": "", "title": "Contract-to-Hire Flexibility"}]', 'Our Project-Based Hiring Approach', 'A structured, outcome-driven method that keeps your project on time and under budget:', '[{"title": "Project Scoping and Role Mapping", "points": ["Decode project goals, timelines, and deliverables", "Map out role requirements and team structure", "Align talent needs with business objectives"]}, {"title": "Talent Pool Activation", "points": ["Tap into curated, skill-based talent pipelines", "Filter by industry expertise and geography", "Prioritize availability and project-readiness"]}, {"title": "Fast-Track Evaluation", "points": ["Conduct quick, targeted technical interviews", "Use assignments and real-world tests", "Assess for both skill and culture fit"]}, {"title": "Deployment and Support", "points": ["Manage onboarding and compliance seamlessly", "Track performance throughout the project lifecycle", "Provide end-to-end support till project wrap-up"]}]', 'Begin the Journey', 'Need Talent That Delivers, Not Just Exists?', 'With Rareminds, get skilled professionals who align with your project from Day OneΓÇöwithout the baggage of long-term hiring. Talk to us and hire the right fit for your next big project.', '2025-05-28 11:08:04.529335', 'Project-Based Hiring Services | On-Demand Talent ', 'Discover RaremindsΓÇÖ Project-Based Hiring solutions; agile, on-demand talent for your fast-moving projects. Hire experts with speed, precision, and zero long-term overhead.'),
	(8, 'psychometric-testing', 'Psychometric Testing Services', 'Hire beyond resumes. Rareminds Psychometric Testing reveals mindset and motivation to ensure your hires thrive, not just survive.', 'Book a Call', 'https://itvhjkgfafikpqmuunlh.supabase.co/storage/v1/object/public/images/Corporate/Recruitment/service/Psychometric-Testing-Services.webp', 'Business professionals analyzing data on digital screens and tablets with colorful abstract graphics ΓÇô concept of data visualization, analytics, teamwork, and digital transformation.', 'Decoding Minds, Not Just Resumes: Rareminds Psychometric Testing', '["Skills get candidates in the door, but mindset, motivation, and fit decide if they thrive. Our psychometric assessments uncover the real drivers behind performance, so you hire not just smart, but right."]', 'What Does Our Psychometric Services Deliver?', 'We combine behavioral science, data analytics, and digital tools to decode how people think, work, and lead at scale.', '[{"t_1": "Validated, Role-Based", "t_2": "Assessments", "points": ["Personality tests aligned to job roles (sales, operations, leadership, tech)", "Cognitive ability, emotional intelligence (EQ), decision-making, and motivation mapping", "Industry-standard tools mapped to benchmarks and job performance"]}, {"t_1": "Science Meets", "t_2": "Simplicity", "points": ["Mobile-friendly tests with adaptive difficulty levels", "Real-time scoring dashboards and benchmark comparisons", "Available in multiple languages for pan-India deployment"]}, {"t_1": "Integrated Hiring", "t_2": "Decisions", "points": ["Combine scores with interviews for final decision-making", "Map cultural fit and team alignment pre-hire", "Use insights to guide onboarding, LandD, and role allocation"]}]', 'Assessment Engagement Models', 'Modular solutions tailored to different phases of your hiring and talent cycle:', '[{"desc": "Screen large applicant pools for aptitude, behavior, and culture fit before interviews.", "icon": "", "title": "Pre-Hire Screening"}, {"desc": "Evaluate decision-making, stress handling, and collaboration at the managerial level.", "icon": "", "title": "Mid-Level Fitment Checks"}, {"desc": "Gauge executive traits like strategic thinking, emotional agility, and influence.", "icon": "", "title": "Leadership Potential Mapping"}, {"desc": "Build role-specific psychometric batteries co-created with your TA and HR teams.", "icon": "", "title": "Custom Assessment Design"}]', 'Our Psychometric Assessment Approach', 'A tight 4-stage model for insight-driven hiring outcomes:', '[{"title": "Role and Competency Mapping", "points": ["Identify must-have traits for role success", "Align with job goals and culture fit", "Build a role-specific competency blueprint"]}, {"title": "Tool and Battery Selection", "points": ["Choose or tailor psychometric assessments", "Match tools to traits and role demands", "Ensure scientific validity and relevance"]}, {"title": "Administer and Analyze", "points": ["Run assessments across candidate pool", "Generate detailed, insight-rich reports", "Highlight strengths, gaps, and patterns"]}, {"title": "Decision Support", "points": ["Provide scorecards and fitment matrices", "Flag potential risks and deal-breakers", "Empower structured, data-backed decisions"]}]', 'Begin the Journey', 'Want to Know Who You''re Hiring?', 'Psychometrics help you go beyond the resumeΓÇöinto mindset, fit, and future performance. Get the science behind smart hiring. LetΓÇÖs test what matters.', '2025-05-28 12:18:00.721438', 'Psychometric Testing Services | Hire Smart with Rareminds Mindset Assessments', 'Rareminds psychometric tests dig deep into mindset, motivation & fit. Boost hires who donΓÇÖt just survive but straight-up thrive.'),
	(11, 'interview-as-a-service', 'Interview-as-a-Service (IaaS)', 'Faster interviews, smarter hires. Rareminds IaaS delivers expert evaluators and flexible scheduling to keep your hiring on point and on pace.', 'Book a Call', 'https://itvhjkgfafikpqmuunlh.supabase.co/storage/v1/object/public/images/Corporate/Recruitment/service/Interview-as-a-Service.webp', 'The image features 2 people displaying a digital screen and the HR is interviewing the lady. Icons representing scheduling, evaluation, and analytics surround the screen, symbolizing the streamlined, tech-driven recruitment process facilitated by IaaS.', 'Streamline Interviews, Speed Up Hiring: Rareminds IaaS', '["Hiring delays? Interview bandwidth issues? We''ve got you. RaremindsΓÇÖ Interview-as-a-Service puts trained evaluators, flexible slots, and structured assessments at your fingertipsΓÇöso your hiring moves faster and smarter."]', 'What Does Our IaaS Model Delivers?', 'From screening to deep-tech rounds, we manage end-to-end interviews with zero load on your internal teams.', '[{"t_1": "Scalable Interview", "t_2": "Bandwidth", "points": ["On-demand access to 500+ certified interviewers across domains", "Technical, functional, behavioral, and leadership interview panels", "24/7 time-zone flexible scheduling for global teams"]}, {"t_1": "Structured, Bias-Free", "t_2": "Evaluation", "points": ["Standardized question banks and evaluation rubrics", "Blind interviews to eliminate bias", "AI-based interview, audio, and quality checks"]}, {"t_1": "Interview Insights", "t_2": "That Matter", "points": ["Real-time feedback dashboards with candidate scoring", "Interview recordings, transcripts, and analytics", "Red flag alerts and hiring recommendations"]}]', 'IaaS Engagement Models', 'Modular support based on your scale and process complexity:', '[{"desc": "We handle all rounds from screening to finalΓÇöacross tech, sales, ops and more.", "icon": "", "title": "End-to-End Interview Outsourcing"}, {"desc": "Deploy pre-vetted interviewers for specific tech stacks or roles.", "icon": "", "title": "Panel-as-a-Service"}, {"desc": "Coordination, scheduling, rescheduling, and candidate communication", "icon": "", "title": "Interview Ops Support"}, {"desc": "Plug our experts to audit and improve your internal interviewing effectiveness.", "icon": "", "title": "Audit and Quality Assurance"}]', 'Our Interview-as-a-Service Approach', 'A structured, scalable model for high-quality interview delivery:', '[{"title": "Role and Round Mapping", "points": ["Set clear role expectations and skills tested", "Design interview rounds and evaluation criteria", "Align rounds with hiring goals"]}, {"title": "Interviewer Allocation", "points": ["Assign certified interviewers by role and level", "Match language and cultural preferences", "Ensure interviewer readiness and training"]}, {"title": "Execution and Evaluation", "points": ["Conduct interviews with live monitoring", "Use standardized scoring and feedback forms", "Apply escalation protocols for edge cases"]}, {"title": "Reporting and Follow-Up", "points": ["Deliver detailed feedback reports", "Share shortlist insights with hiring managers", "Prepare candidates and teams for next steps"]}]', 'Begin the Journey', 'Make Interviews Your Strength, Not Your Bottleneck', 'Faster decisions. Better candidates. Zero chaos. Rareminds IaaS is the recruitment hack your hiring team has been waiting for. Talk to us and scale your interviewsΓÇölike a pro.', '2025-05-29 04:31:51.925297', 'Interview-as-a-Service (IaaS) | Fast, Scalable Interview Solutions ΓÇô Rareminds', 'Accelerate hiring with Rareminds'' Interview-as-a-Service. Access 500+ expert interviewers, bias-free assessments, and real-time insights. Streamline interviews, improve quality, and scale faster.'),
	(4, 'behavioral-culture-fit-assessments', 'Behavioral & Culture Fit Assessments', 'Skills get the job done. Mindset makes it last. RaremindsΓÇÖ Behavioral and Culture-Fit Assessments ensure every hire clicks with your team, values, and vision.', 'Book a Call', 'https://itvhjkgfafikpqmuunlh.supabase.co/storage/v1/object/public/images/Corporate/Recruitment/service/Behavioral-and-Culture-Fit.webp', 'Illustration of a professional man seated at a desk surrounded by colorful geometric shapes, working on a laptop with digital sticky notes floating in the air.', 'Hire for Mindset, Not Just Skillset: Rareminds Behavioral and Culture Fit Services', '["Great hiring isnΓÇÖt just about skillsΓÇöitΓÇÖs about synergy. At Rareminds, we assess the ΓÇ£howΓÇ¥ behind the ΓÇ£whatΓÇ¥ to ensure every hire blends seamlessly with your team culture, work style, and growth trajectory."]', 'What Does Our Behavioral and Cultural Fit Assessments Deliver?', 'Our assessments are designed to identify behavioral strengths, personality traits, and cultural alignment, helping you build resilient, value-driven teams.', '[{"t_1": "Behavioral Insight", "t_2": "that Drives Performance", "points": ["Personality profiling and role-behavior alignment", "Leadership readiness and adaptability scores", "Predictive analytics for attrition risk and team fit"]}, {"t_1": "Culture Fit,", "t_2": "Quantified", "points": ["Custom-fit benchmarks mapped to your organizationΓÇÖs core values", "Role-specific culture indicators for tech, sales, operations and leadership", "Scoring models that flag alignment gaps before hiring"]}, {"t_1": "Hiring Support", "t_2": "That Reduces Friction", "points": ["Fitment dashboards for HR and line managers", "Panel-ready interview templates and structured feedback forms", "Team-level compatibility scoring for better onboarding planning"]}]', 'Assessment Engagement Models', 'Choose the right-fit model based on your hiring volume, timeline, and depth of evaluation needed:', '[{"desc": "Id