	(12, 'pre-onboarding-support', 'Pre-Onboarding Support', 'Starting strong means starting smart. RaremindsΓÇÖ Pre-Onboarding Support sets the stage for seamless new hire, ensuring your talent hits the ground sprinting.', 'Book a Call', 'https://itvhjkgfafikpqmuunlh.supabase.co/storage/v1/object/public/images/Corporate/Recruitment/service/Pre-Onboarding-Support.webp', 'Image showing 4 people holding documents discussing worklife and pre-on boarding support in a simplified way.', 'Day One? TheyΓÇÖre Already Winning.', '["Great onboarding doesnΓÇÖt begin with introducing yourself on Day One. It starts before thatΓÇöwith the right first impression, the right tools, and the right energy. RaremindsΓÇÖ Pre-Onboarding Support helps you turn fresh hires into confident contributors before they even log in."]', 'What Does Our Pre-Onboarding Support Deliver?', 'We make sure the handoff from offer to first day is flawlessΓÇöbecause every missed email or unanswered question costs time and talent.', '[{"t_1": "Clear Communication", "t_2": "and Documentation", "points": ["Timely sharing of offer letters, contracts, and policy documents", "Transparent info on company culture, dress code, and work hours", "Dedicated pre-joining helpdesk for FAQs and concerns"]}, {"t_1": "Tech Setup and", "t_2": "Compliance Checks", "points": ["Guidance on IT access, hardware needs, and software installs", "Collection and verification of essential documents before Day 1", "Background checks and compliance protocols handled smoothly"]}, {"t_1": "Engagement and", "t_2": "Orientation Prep", "points": ["Pre-joining welcome kits and company swag to build excitement", "Introductory videos and virtual meet-and-greets with teams and managers", "Scheduling first-week training and orientation sessions"]}]', 'Our Pre-Onboarding Support Models', 'Pick your power move, tailored to your scale and vibe:', '[{"desc": "We handle everything from offer acceptance to Day 1 readinessΓÇöno stress, no mess.", "icon": "", "title": "Full Ownership Mode"}, {"desc": "Our pre-onboarding pros personally coach and support candidates for a smooth ride.", "icon": "", "title": "Dedicated Talent Guides"}, {"desc": "Focus on IT setup and background checks, so no tech or compliance curveballs on Day 1.", "icon": "", "title": "Tech-Ready and Compliant"}, {"desc": "Jump in with only the services you need, perfectly customized to your company culture.", "icon": "", "title": "Plug-and-Play Support"}]', 'Our Pre-Onboarding Approach', 'How we nail pre-onboarding in 4 steps:', '[{"title": "Blueprint and Map It Out", "points": ["Outline candidate journey, role, and timelines", "Define tech and process requirements upfront", "Set expectations for all stakeholders"]}, {"title": "Communication and Connect", "points": ["Send clear, timely updates and reminders", "Share welcome kits and FAQs to hype candidates", "Keep engagement high throughout pre-joining"]}, {"title": "Verify and Setup", "points": ["Complete document verification and background checks", "Set up secure IT and system access pre-Day 1", "Ensure compliance and readiness before onboarding"]}, {"title": "Welcome and Engage", "points": ["Schedule intros, orientation, and training sessions", "Create a warm, inclusive Day 1 experience", "Kickstart engagement to boost retention"]}]', 'Begin the Journey', 'DonΓÇÖt Let Your Talent Drift Before Day One.', 'RaremindsΓÇÖ Pre-Onboarding Support keeps your pipeline hot and your hires ready. Say goodbye to no-shows and slow startersΓÇötalk to us today and build a workforce thatΓÇÖs onboarded right from the jump!', '2025-05-29 04:46:39.319578', 'Pre-Onboarding Support | Rareminds ΓÇô Set New Hires Up to Win from Day One', 'Start strong with RaremindsΓÇÖ Pre-Onboarding Support. Seamless communication, tech setup, and engagement ensure your hires hit the ground running before Day One.');
INSERT INTO "public"."training_services" ("id", "title", "description", "feature_badges", "programs", "created_at", "updated_at") VALUES
	('communication-collaboration', 'Communication and Collaboration', 'Master the art of effective communication and foster collaborative excellence across teams and stakeholders.', '["Public Speaking", "Cross-Cultural Communication", "Virtual Collaboration", "Presentation Skills"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('workplace-productivity', 'Workplace Productivity', 'Optimize performance and efficiency through proven productivity methodologies and time management strategies.', '["Time Management", "Goal Setting", "Process Optimization", "Work-Life Balance"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('digital-tech', 'Digital and Technology Skills', 'Stay ahead in the digital age with cutting-edge technology skills and digital transformation capabilities.', '["AI/ML Basics", "Data Analytics", "Digital Tools", "Tech Adoption"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('sales-marketing-customer', 'Sales, Marketing and Customer Centricity', 'Drive revenue growth and customer satisfaction through advanced sales techniques and customer-centric strategies.', '["Sales Excellence", "Customer Experience", "Marketing Strategy", "CRM"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('hr-talent-development', 'HR and Talent Development', 'Build world-class HR capabilities and talent development programs that attract, develop, and retain top talent.', '["Talent Management", "Performance Management", "Employee Development", "HR Analytics"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('custom-corporate-academies', 'Custom Corporate Academies', 'Design and implement bespoke learning academies tailored to your organization''s specific needs and culture.', '["Custom Curriculum", "Learning Management", "Blended Learning", "Certification"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('behavioral-culture', 'Behavioral and Organizational Culture', 'Transform workplace culture and individual behaviors to create high-performing, values-driven organizations.', '["Culture Assessment", "Behavioral Change", "Values Alignment", "Employee Engagement"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('leadership-management', 'Leadership and Management Excellence', 'Develop visionary leaders who can think strategically, lead with empathy, and execute with clarity. Whether it''s a first-time manager or a CXO, our programs build a strong foundation for people leadership and organizational growth. Perfect for navigating complexity with confidence.', '[{"bg": "bg-blue-50", "icon": "users", "text": "Expert-Led Training", "color": "text-blue-700"}, {"bg": "bg-purple-50", "icon": "brain", "text": "Practical Learning", "color": "text-purple-700"}, {"bg": "bg-indigo-50", "icon": "target", "text": "Measurable Results", "color": "text-indigo-700"}]', '[{"id": "first-time-manager", "cta": {"text": "Let''s grow your next-gen leadership bench.", "description": "Don''t leave your future leaders to figure it out alone. Equip your team with the tools, mindset, and confidence to lead people, not just processes. Book this program today and start building leadership from day one. Connect with us to customize the First-Time Manager to People Leader Program for your team."}, "title": "First-Time Manager to People Leader", "modules": [{"hours": "4 hrs", "title": "Decode Leadership DNA", "outcome": "Understand your leadership persona", "activities": "Digital tool: Crystal Knows + RolePlay", "objectives": "Self-discovery through gamified psychometric tools"}, {"hours": "5 hrs", "title": "Gen Z x Boomers ΓÇô People Sync 101", "outcome": "Build an inclusive team leadership style", "activities": "Cross-age mock interviews, AI-analyzed feedback", "objectives": "Generational empathy through reverse mentoring and age-diverse team simulations"}, {"hours": "6 hrs", "title": "Empathy & Influence Lab", "outcome": "Develop human-centered leadership", "activities": "Oculus walkthroughs, Impact Story Circles", "objectives": "VR-enabled empathy walks + Story-based learning"}, {"hours": "5 hrs", "title": "Talk Like a Leader", "outcome": "Master team communication and crisis talk", "activities": "Use AI tools like Yoodli + TalkTech Battle", "objectives": "AI-led voice modulation, storytelling & difficult conversations"}, {"hours": "4 hrs", "title": "Agile Mindset, Not a Jargon", "outcome": "Develop agile thinking + fast decision-making", "activities": "Agile sprint simulation, meme-based learning", "objectives": "Microlearning sprints + Real-time Slack challenges"}, {"hours": "5 hrs", "title": "Coaching over Commanding", "outcome": "Create a coaching culture over micromanagement", "activities": "Coaching journals, Buddy sessions", "objectives": "Peer-to-peer coaching pods + Feedback journaling"}, {"hours": "5 hrs", "title": "Conflict ΓåÆ Construct", "outcome": "Learn structured conflict resolution", "activities": "Conflict maps + Role reversals", "objectives": "Simulated conflict zones using branching scenarios"}, {"hours": "5 hrs", "title": "Data-Driven Leadership", "outcome": "Interpret data to drive people''s decisions", "activities": "Use Notion + KPI Dashboards", "objectives": "Gamified dashboards + Leaderboards"}, {"hours": "3 hrs", "title": "Culture Design Bootcamp", "outcome": "Create your team culture playbook", "activities": "Canva-based design, Team rituals toolkit", "objectives": "Team culture canvas + AI Culture Scans"}, {"hours": "3 hrs", "title": "Hack Your Growth Plan", "outcome": "Build a 6-month leadership growth sprint", "activities": "Personal Career Hackathon", "objectives": "Create a Growth Roadmap + Learning NFTs"}], "delivery": ["Scenario-Based Learning: Real-world challenges, not theoretical lectures.", "Expert-Led Sessions: Insights from leadership veterans and industry coaches.", "Behavioral Assessments: Self-awareness that sparks self-leadership.", "Post-Training Nudges: Microlearnings and manager toolkits that stick."], "overview": "Promoting top performers into management without training is a fast track to team chaos and burnout. Rareminds'' First-Time Manager to People Leader program transforms individual contributors into confident, people-first leaders equipped to inspire, execute, and grow high-performance teams. With over 20 years of experience, our program fast-tracks emerging managers into confident communicators, decision-makers, and culture builders who lead with impact from day one.", "whyChoose": "Because we build leaders who last. With a legacy of 20+ years, Rareminds helps organizations future-proof their leadership pipeline by transforming first-time managers into capable, people-savvy, business-aligned leaders.", "whatWeCover": ["Mindset to Manager: Transition from Individual Contributor to Team Enabler with Clarity and Confidence.", "Leading People, Driving Performance: Build trust, manage conflicts, and motivate teams with emotional intelligence.", "Strategic Delegation and Smart Decision-Making: Execute with ownership, agility, and alignment to business outcomes.", "Manager as Coach: Deliver feedback that drives growth, accountability, and high performance."]}, {"id": "strategic-thinking", "cta": {"text": "Stop playing catch-up. Train your teams to think two steps ahead with data-driven decisions and strategic clarity.", "description": "Equip your leaders with the edge to outthink and outpace the competition. Let''s build a culture of bold, future-ready leaders. Let''s customize the Strategic Thinking and Decision Making program for your organization today."}, "title": "Strategic Thinking and Decision Making", "modules": [{"hours": "4 hrs", "title": "Strategy Mindset Shift", "outcome": "Develop a flexible, future-ready strategic mindset", "activities": "Interactive scenario puzzles + Strategy games", "objectives": "Understand strategic thinking as a dynamic, creative mindset"}, {"hours": "5 hrs", "title": "Systems Thinking & Pattern Recognition", "outcome": "Spot systemic leverage points for smarter moves", "activities": "Digital causal loop mapping + Pattern quizzes", "objectives": "Learn to see big-picture interconnections & predict outcomes"}, {"hours": "5 hrs", "title": "Hypothesis-Driven Decision Making", "outcome": "Make confident, data-backed choices", "activities": "Real-time case simulations + Hypothesis canvas", "objectives": "Use hypothesis framing to reduce uncertainty in decisions"}, {"hours": "5 hrs", "title": "Bias Busting & Critical Thinking", "outcome": "Sharpen objective and inclusive decision-making", "activities": "AI-assisted bias detector + Group debates", "objectives": "Identify & neutralize cognitive biases affecting judgment"}, {"hours": "5 hrs", "title": "Scenario Planning & Futurecasting", "outcome": "Anticipate challenges & opportunities", "activities": "VR futureworld simulations + Collaborative storyboarding", "objectives": "Craft multiple future scenarios to prepare for uncertainty"}, {"hours": "4 hrs", "title": "Data-Driven Strategic Insights", "outcome": "Lead with evidence-backed strategies", "activities": "Gamified dashboards + Data storytelling tools", "objectives": "Translate complex data into actionable strategic insights"}, {"hours": "5 hrs", "title": "Agile Decision Cycles", "outcome": "Adapt strategies quickly and smartly", "activities": "Agile sprint decision games + Retrospective tools", "objectives": "Implement rapid, iterative decision-making cycles"}, {"hours": "4 hrs", "title": "Stakeholder Mapping & Influence", "outcome": "Build strategic alliances & influence effectively", "activities": "Stakeholder mapping software + Role-play", "objectives": "Identify key stakeholders and tailor communication strategies"}, {"hours": "4 hrs", "title": "Risk Radar & Mitigation Plans", "outcome": "Minimize surprises, maximize resilience", "activities": "Interactive risk simulations + Mitigation planning templates", "objectives": "Develop proactive risk identification and response frameworks"}, {"hours": "3 hrs", "title": "Strategic Growth Hackathon", "outcome": "Create a viable, innovative strategic growth plan", "activities": "Live virtual hackathon + Real-time coaching", "objectives": "Apply all learning in a live business challenge with peer feedback"}], "delivery": ["Case-Driven Workshops: Strategy simulations and business war games.", "Facilitator-Led Discussions: Insights from C-suite mentors and strategic consultants.", "Decision Labs: Hands-on exercises for bias-breaking, prioritization, and scenario planning.", "Action Plans and Playbooks: Practical frameworks your leaders can apply immediately."], "overview": "Running on gut instinct in today''s business world is a shortcut to costly mistakes and missed growth. In business, reactive thinking won''t cut it. Organizations need leaders who see beyond the nowΓÇöwho can anticipate trends, make sharp decisions, and align every move with the bigger picture. That''s exactly what Rareminds'' Strategic Thinking and Decision Making program delivers. Designed for mid-to-senior leaders and high-potential managers, this training sharpens their ability to think critically, plan proactively, and lead decisively even in high-stakes environments. It''s not just about being smart, but thinking strategically smart.", "whyChoose": "Rareminds'' Strategic Thinking and Decision Making program helps your managers and leaders rise above the noise, analyze complexity, and make bold, calculated decisions that drive sustainable success.", "whatWeCover": ["Strategic Mindset Building: Shift from operational fix-it mode to long-term value creation.", "Decision Frameworks:  Tools and models to make timely, data-driven, risk-aware choices.", "Problem-Solving Under Pressure: Real-world scenarios that demand agility, clarity, and focus.", "Business Alignment: Ensuring every decision supports organizational goals and growth."]}, {"id": "emotional-intelligence", "cta": {"text": "Your teams don''t need more managers, but emotionally intelligent leaders.", "description": "Turn your managers into motivators who lead with empathy and insight. Enroll now to build high-performing, emotionally connected teams. Let''s design your custom Leading with Emotional Intelligence journey today."}, "title": "Leading with Emotional Intelligence", "modules": [{"hours": "4 hrs", "title": "Emotional Intelligence 101", "outcome": "Identify and map your emotional strengths and gaps", "activities": "Interactive EI quizzes + Self-reflection journals", "objectives": "Understand EI fundamentals and self-awareness"}, {"hours": "5 hrs", "title": "Mastering Self-Regulation", "outcome": "Stay cool under pressure and bounce back faster", "activities": "Biofeedback apps + Mindfulness VR sessions", "objectives": "Develop impulse control and emotional resilience"}, {"hours": "5 hrs", "title": "Social Awareness & Empathy Lab", "outcome": "Read and respond to emotions in your team like a pro", "activities": "VR empathy walks + Real-time social cue decoding", "objectives": "Sharpen empathy and active listening skills"}, {"hours": "5 hrs", "title": "Emotionally Intelligent Communication", "outcome": "Connect deeply, influence effectively", "activities": "AI-powered speech analysis + Role-play difficult convos", "objectives": "Communicate with impact while managing emotional undercurrents"}, {"hours": "5 hrs", "title": "Managing Conflict with EQ", "outcome": "Turn conflict into collaboration", "activities": "Interactive conflict simulations + Emotion tracking", "objectives": "Use emotional intelligence to de-escalate and resolve conflicts"}, {"hours": "4 hrs", "title": "Building Psychological Safety", "outcome": "Create a fearless, high-performing team culture", "activities": "Team trust-building games + Anonymous feedback tools", "objectives": "Foster trust and open dialogue in teams"}, {"hours": "5 hrs", "title": "Coaching Through Emotional Lens", "outcome": "Empower and motivate your people authentically", "activities": "Peer coaching pods + Reflective journaling", "objectives": "Use EI to inspire and develop others"}, {"hours": "4 hrs", "title": "Leading with Compassion", "outcome": "Lead with heart without losing focus on results", "activities": "Compassion mapping exercises + Case studies", "objectives": "Balance empathy with accountability"}, {"hours": "4 hrs", "title": "Emotional Intelligence Metrics", "outcome": "Quantify emotional leadership effectiveness", "activities": "EI assessment dashboards + Progress analytics", "objectives": "Measure and track EI growth and impact"}, {"hours": "3 hrs", "title": "EQ Leadership Capstone", "outcome": "Own your emotional intelligence as a leader", "activities": "Virtual leadership simulations + Expert feedback", "objectives": "Integrate EI learnings in a live leadership challenge"}], "delivery": ["Interactive Workshops: Roleplays, empathy maps, and reflection exercises.", "Real-Time Coaching: Personal feedback from certified facilitators.", "Emotional Intelligence Assessments: Identify blind spots and growth areas.", "Follow-Up Reinforcement: Nudges, toolkits, and manager reflection journals."], "overview": "Leaders without emotional intelligence don''t just failΓÇöthey take their teams down with them. In the age of AI and automation, emotional intelligence (EQ) is the human superpower that sets exceptional leaders apart. At Rareminds, our Leading with Emotional Intelligence program helps leaders master the art of connecting with people, navigating complexity, and influencing outcomes with empathy and authenticity. This is not about being \"soft.\" It''s about being smart with emotions; your own and others. When leaders lead with EQ, they build stronger teams, reduce attrition, and drive performance through trust and motivation.", "whyChoose": "Because EQ(Emotional Quotient) isn''t a buzzword but a business strategy. With 20+ years of experience, Rareminds enables leaders to turn emotional insight into strategic influence, improving team cohesion, engagement, and bottom-line impact.", "whatWeCover": ["Self-Awareness and Self-Regulation: Recognize emotional triggers and respond, not react.", "Empathy in Action: Understand unspoken signals, listen deeply, and build real trust.", "Social Awareness and Relationship Management: Manage dynamics, resolve conflicts, and influence positively.", "Leadership Presence: Create emotional impact and inspire loyalty, even in tough times."]}, {"id": "change-management", "cta": {"text": "If your organization is evolving, your leaders should be too.", "description": "Change waits for no one. Equip your leaders with the mindset and skills to navigate disruption and lead transformation with confidence. Start your agility upgrade; talk to us today."}, "title": "Change Management and Agility", "modules": [{"hours": "4 hrs", "title": "Change Mindset Reset", "outcome": "Build a positive, flexible approach to change", "activities": "Interactive mindset assessments + Growth mindset games", "objectives": "Break mental barriers, embrace change as a growth driver"}, {"hours": "5 hrs", "title": "Agile Foundations 101", "outcome": "Speak agile fluently and apply basics to your team", "activities": "Agile simulations + Kanban boards", "objectives": "Understand core agile principles and frameworks"}, {"hours": "5 hrs", "title": "Leading Through Change", "outcome": "Guide your crew with calm & clarity", "activities": "Scenario-based role plays + Emotional resilience VR", "objectives": "Lead teams confidently during uncertainty"}, {"hours": "5 hrs", "title": "Communication in Flux", "outcome": "Keep stakeholders engaged and aligned", "activities": "AI-driven communication audits + Storytelling labs", "objectives": "Master transparent and adaptive communication during change"}, {"hours": "5 hrs", "title": "Building Agile Teams", "outcome": "Build squads that pivot fast and deliver consistently", "activities": "Team agility challenges + Retrospective tools", "objectives": "Create high-performing, cross-functional agile teams"}, {"hours": "4 hrs", "title": "Digital Tools for Change", "outcome": "Use digital muscle to manage workflows and feedback", "activities": "Toolkits on Jira, Trello, Slack integrations", "objectives": "Leverage tech for smoother change management"}, {"hours": "5 hrs", "title": "Overcoming Resistance", "outcome": "Neutralize blockers with empathy and strategy", "activities": "Behavioral simulations + Resistance mapping", "objectives": "Spot & address resistance before it derails progress"}, {"hours": "4 hrs", "title": "Rapid Experimentation & Feedback Loops", "outcome": "Test, learn, adapt ΓÇö fast and smart", "activities": "Real-time MVP builds + Feedback gamification", "objectives": "Use MVPs and feedback to accelerate change"}, {"hours": "4 hrs", "title": "Measuring Change Impact", "outcome": "Stay data-driven, flexible, and outcome-focused", "activities": "Dashboards + Data visualization workshops", "objectives": "Track change KPIs and adjust course in real time"}, {"hours": "3 hrs", "title": "Change & Agility Sprint Hackathon", "outcome": "Own change and agility as everyday leadership skills", "activities": "Virtual sprint + Peer and expert feedback", "objectives": "Apply learning in a live sprint challenge"}], "delivery": ["Simulated Change Labs: Real-life business disruptions, live decision-making.", "Agile Frameworks and Tools: Kanban, SCRUM basics, and lean change techniques.", "Facilitator-Guided Playbooks: Strategy to communicationΓÇöeverything leaders need.", "Post-Training Resources: Agility trackers, feedback loops, and change-readiness kits."], "overview": "Lead Change. Pivot Fast. Build Adaptive Teams. Disruption is the new default. Whether it''s digital transformation, organizational restructuring, or market volatility. Rareminds'' Change Management and Agility program equips your leaders to not only manage change but to own it, pivot fast, and lead teams confidently through uncertainty. This isn''t about resistance management rather about future-forward leadership. We train your managers to navigate ambiguity, build resilient teams, and turn chaos into opportunity.", "whyChoose": "Because we don''t just teach changeΓÇöwe''ve been a part of it for over 20 years. From tech firms to legacy enterprises, Rareminds has enabled organizations to embed agility, reduce disruption fatigue, and build change-resilient leadership across every layer.", "whatWeCover": ["Change Leadership Mindset: Shift from reactive to proactive change champions.", "Agility in Action: Build adaptive thinking, rapid decision-making, and flexible execution.", "Overcoming Resistance: Tools to manage emotions, address fears, and foster buy-in.", "Sustaining Momentum: Drive continuous improvement and embed agility in culture."]}, {"id": "coaching-mentoring", "cta": {"text": "Ready to turn your managers into growth enablers?", "description": "Managers don''t grow teams by giving orders; they grow them by coaching. Build a workplace where knowledge is shared, potential is unlocked, and leaders invest in people. Launch this program and create a mentoring culture that scales. Let''s build your custom Coaching and Mentoring Skills program together."}, "title": "Coaching and Mentoring Skills", "modules": [{"hours": "4 hrs", "title": "Coaching vs. Mentoring 101", "outcome": "Know when to coach, when to mentor ΓÇö and how to do both", "activities": "Real-life case debates + Coaching-Mentoring matrix", "objectives": "Understand the distinction and power of both approaches"}, {"hours": "5 hrs", "title": "Building Trust & Connection", "outcome": "Establish safe, open coaching environments", "activities": "Trust accelerators toolkit + Empathy speed rounds", "objectives": "Learn the neuroscience of trust and how to create psychological safety"}, {"hours": "5 hrs", "title": "Active Listening Mastery", "outcome": "Level up presence and deep listening in every conversation", "activities": "Listening labs + Eye contact VR challenges", "objectives": "Deep dive into non-verbal cues, active listening, and mindful silence"}, {"hours": "5 hrs", "title": "Asking Powerful Questions", "outcome": "Shift from advising to guiding with impact", "activities": "Question storming games + AI-powered question coach", "objectives": "Use inquiry to unlock insight, motivation, and ownership"}, {"hours": "5 hrs", "title": "Feedback Without Fear", "outcome": "Give and receive feedback like a pro", "activities": "FeedForward simulations + SBI technique roleplays", "objectives": "Deliver tough feedback with tact and emotional intelligence"}, {"hours": "4 hrs", "title": "Goal Setting with Coachees", "outcome": "Drive action through structured, coach-led goal alignment", "activities": "Goal Canvas + Coaching Planner Toolkit", "objectives": "Use GROW, CLEAR & OKR models to co-create goals"}, {"hours": "4 hrs", "title": "Digital Coaching Ecosystem", "outcome": "Run coaching at scale with smart systems", "activities": "Tools: CoachAccountable, Notion templates, Slack bots", "objectives": "Integrate coaching with digital tools for scalability"}, {"hours": "5 hrs", "title": "Peer Mentoring & Reverse Coaching", "outcome": "Promote cross-generational, 360┬░ learning cultures", "activities": "Reverse mentoring pods + Peer coaching exchanges", "objectives": "Develop lateral and upward mentoring capabilities"}, {"hours": "4 hrs", "title": "Handling Coaching Resistance", "outcome": "Manage tough mentees and unblock mindset barriers", "activities": "Resistance response games + Coaching journal reviews", "objectives": "Spot resistance patterns and pivot coaching style accordingly"}, {"hours": "4 hrs", "title": "Capstone: Coaching in Action", "outcome": "Practice-ready, feedback-hardened coaching confidence", "activities": "Recorded coaching sessions + Group debrief circles", "objectives": "Run a full coaching session + mentoring map with feedback"}], "delivery": ["Live Practice Labs: Real coaching sessions, real-time feedback.", "Mentor Frameworks and Models: GROW, CLEAR, and other proven approaches.", "Interactive Roleplays: Practical tools to handle tough mentoring moments.", "Follow-Through Tools: Coaching journals, feedback templates, and progress maps."], "overview": "Managers who can''t coach are just bottlenecks with authority. Grow People. Unlock Potential. Create Legacy. Great managers get the job done. Exceptional leaders grow people while doing it. Rareminds'' Coaching and Mentoring Skills program is designed to help your leaders step into that next level, where they don''t just guide performance but shape potential. Coaching is no longer optional but essential. This program empowers leaders to have meaningful conversations, unlock talent, and build high-performing, self-driven teams through consistent mentoring and feedback.", "whyChoose": "Because growing leaders isn''t a one-time eventΓÇöit''s a continuous journey. With 20+ years of expertise, Rareminds partners with organizations to create a culture where coaching is embedded, mentoring is intentional, and leadership is multiplied.", "whatWeCover": ["Coaching Mindset: Shift from directing to developing. Ask more, tell less.", "Mentoring Conversations: Build trust, share wisdom, and create growth paths.", "Active Listening and Powerful Questioning: Get to the root of challenges, not just symptoms.", "Feedback That Fuels: Deliver insights that inspire change, not resistance."]}, {"id": "okr-performance", "cta": {"text": "Turn your managers into goal-getters and performance drivers.", "description": "Your business goals are only as strong as your team''s alignment. Train your leaders to set clear OKRs and have performance conversations that drive results, not just reviews. Book this program to turn intentions into execution. Let''s customize your OKR/Goal Setting and Performance Conversations journey today."}, "title": "OKR(Objectives and Key Results) and Performance Conversations", "modules": [{"hours": "4 hrs", "title": "The Goal-Setting Shift", "outcome": "Build clarity on strategic vs. tactical goal systems", "activities": "Story-led failures + OKR vs. KPI debates", "objectives": "Understand why traditional goal-setting fails and how OKRs change the game"}, {"hours": "5 hrs", "title": "Writing Killer OKRs", "outcome": "Create aligned, stretch-but-realistic OKRs", "activities": "OKR writing lab + Peer reviews using GPT critique bots", "objectives": "Learn to craft inspiring Objectives and measurable Key Results"}, {"hours": "5 hrs", "title": "Cascading OKRs Across Teams", "outcome": "Connect company vision to individual goals seamlessly", "activities": "Notion/ClickUp OKR boards + Role-based OKR sync drills", "objectives": "Align top-down and bottom-up OKRs across departments"}, {"hours": "4 hrs", "title": "Micro-goals & Accountability Hacks", "outcome": "Turn intentions into execution rituals", "activities": "Habit tracker setup + Accountability pods", "objectives": "Break big goals into weekly habits and check-ins"}, {"hours": "5 hrs", "title": "Real Talk: Performance Conversations", "outcome": "Ditch annual reviews for consistent, empowering convos", "activities": "Simulation battles + AI-led tone analysis (Yoodli, Loomie)", "objectives": "Build confidence in giving regular, human-centered performance feedback"}, {"hours": "4 hrs", "title": "Feedback Frameworks That Work", "outcome": "Give feedback that motivates, not demoralizes", "activities": "Feedback roulette + Coaching dojo", "objectives": "Use tools like SBI, FeedForward, and Radical Candor"}, {"hours": "4 hrs", "title": "Managing Up, Sideways & Remote", "outcome": "Lead aligned execution in all directions", "activities": "OKR sync challenge + Influence grid mapping", "objectives": "Drive goal alignment across managers, peers, and remote teams"}, {"hours": "5 hrs", "title": "Coaching for Performance", "outcome": "Unlock underperformance through mindset and skills coaching", "activities": "Obstacle mapping + ''Stuck-to-Shift'' toolkits", "objectives": "Use coaching tools to address blockers and energize performance"}, {"hours": "4 hrs", "title": "Data-Driven Progress Tracking", "outcome": "Build a transparent, growth-based performance culture", "activities": "Dashboards, KPI health checks + Leaderboards", "objectives": "Use analytics to measure performance without micromanaging"}, {"hours": "5 hrs", "title": "Performance Conversations Live Lab", "outcome": "Leave with real experience of high-trust, high-impact convos", "activities": "Live performance conversation simulation + peer debriefs", "objectives": "Practice full-cycle goal setting + review conversation"}], "delivery": ["Goal-Setting Simulations: Real-business OKR exercises with measurable outputs.", "Manager Toolkits: Templates, prompts, and tracking tools for immediate use.", "Live Feedback Clinics: Practice tough conversations with expert coaching.", "Post-Training Support: Review formats, performance dashboards, and reinforcement nudges."], "overview": "No clear goals? Then expect unclear outcomes and underperformance, every single time. Align Goals. Drive Performance. Fuel Growth. Goals without clarity are just checkboxes. Feedback without strategy is just noise. At Rareminds, our Objectives and Key Results /Goal Setting and Performance Conversations program equips leaders to align teams with what truly moves the businessΓÇöand to drive accountability through powerful, ongoing performance dialogues. This is where goal-setting meets execution. Leaders learn to define clear objectives, break silos, and make performance conversations a growth tool, not a once-a-year ritual.", "whyChoose": "Because goal-setting isn''t about more tasksΓÇöit''s about better results. With 20+ years of transforming leadership performance, Rareminds helps organizations create clarity, boost engagement, and drive a culture where goals are owned and outcomes are celebrated.", "whatWeCover": ["Framework Mastery: Set ambitious, aligned, and outcome-focused goals.", "Cascading Goals Across Teams: Ensure everyone''s rowing in the same direction.", "Effective Performance Conversations: Make feedback timely, actionable, and future-focused.", "Tracking and Accountability: Build momentum with check-ins, reviews, and data-led insights."]}, {"id": "high-trust-teams", "cta": {"text": "Ready to turn teams into trust-powered engines of performance?", "description": "High performance starts with high trust. If your teams donΓÇÖt feel safe, heard, and valuedΓÇöthey wonΓÇÖt show up with their best. Build trust like itΓÇÖs your most valuable currencyΓÇöbecause it is. LetΓÇÖs design your custom Building High-Trust Teams program today."}, "title": "Building High-Trust Teams", "modules": [{"hours": "4 hrs", "title": "Trust is the New Currency", "outcome": "Recognize trust gaps and make the business case for trust", "activities": "BrainTrust simulation + Trust audit toolkit", "objectives": "Understand the neuroscience and ROI of trust in teams"}, {"hours": "5 hrs", "title": "Psychological Safety: More Than a Buzzword", "outcome": "Embed psychological safety in team culture", "activities": "Virtual ΓÇ£failure partiesΓÇ¥ + Safety scorecards", "objectives": "Cultivate environments where teams feel safe to speak up and show up"}, {"hours": "5 hrs", "title": "Decode the Trust Equation", "outcome": "Build a trust-first reputation as a team leader", "activities": "Trust canvas + Personal brand SWOT", "objectives": "Learn & apply the trust equation: Credibility + Reliability + Intimacy / Self-interest"}, {"hours": "4 hrs", "title": "Transparency Without Chaos", "outcome": "Improve clarity, reduce confusion, increase alignment", "activities": "Slack transparency drills + Notion dashboards", "objectives": "Learn radical transparency without over-sharing or overloading"}, {"hours": "5 hrs", "title": "Feedback Culture ΓåÆ Real-Time Trust", "outcome": "Turn friction into stronger team dynamics", "activities": "Feedforward sessions + Conflict role reversals", "objectives": "Normalize feedback and conflict as trust builders"}, {"hours": "4 hrs", "title": "Trust in Hybrid & Remote Teams", "outcome": "Build bonds across screens and time zones", "activities": "Remote empathy simulations + Async trust toolkit", "objectives": "Tackle distance bias and trust erosion in hybrid setups"}, {"hours": "4 hrs", "title": "Role Clarity = Less Drama", "outcome": "Ensure everyone knows their lane, without silos", "activities": "Role Chartering + Team OS mapping", "objectives": "Eliminate confusion and unspoken assumptions"}, {"hours": "5 hrs", "title": "Empathy-Driven Team Building", "outcome": "Create teams that see each other beyond job titles", "activities": "Virtual empathy walks + Identity exchange challenges", "objectives": "Drive connection and inclusion through empathy"}, {"hours": "5 hrs", "title": "Accountability with Compassion", "outcome": "Build mutual respect & self-leadership across the team", "activities": "Ownership ladder game + Responsibility matrix workshops", "objectives": "Balance ownership with empathy, tough love with support"}, {"hours": "4 hrs", "title": "Team Trust Lab", "outcome": "Build your own team trust playbook and action plan", "activities": "Team design sprint + Trust retro hackathon", "objectives": "Practice building trust through real-time case challenges"}], "delivery": ["Real-World Team Scenarios: Practice conversations and collaboration challenges.", "Trust-Building Frameworks: Lencioni, Covey, and evidence-backed models.", "Interactive Group Exercises: Break silos and strengthen intra-team dynamics.", "Ongoing Trust Metrics: Simple tools to measure and maintain team trust levels."], "overview": "Without trust, even the smartest teams fall apart under pressure. So, Build Trust, Build Culture, Build Results. Without trust, teams stall. With it, they scale. RaremindsΓÇÖ Building High-Trust Teams program helps leaders create psychologically safe, high-performing environments where collaboration thrives, feedback flows, and people bring their best to the tableΓÇöevery single day. Trust isnΓÇÖt built in a day, but it can be trained, modeled, and multiplied. This program empowers leaders to foster transparency, accountability, and connection, turning teams into tight-knit, purpose-driven units.", "whyChoose": "Because high trust isn''t just a soft skill, but a high-return strategy. With 20+ years of experience, Rareminds helps organizations build leadership that fuels unity, boosts engagement, and drives performance from the inside out.", "whatWeCover": ["Foundations of Trust: Understand the core pillars: credibility, reliability, and intent.", "Psychological Safety: Create a no-blame, high-growth space where people speak up.", "Handling Conflicts Constructively: Navigate tension without breaking trust.", "Trust-Building Behaviors: Lead with consistency, empathy, and clear communication."]}]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00'),
	('strategic-addons', 'Add-Ons for Strategic Advantage', 'Enhance your training programs with strategic add-ons including coaching, assessments, and continuous learning support.', '["Executive Coaching", "360┬░ Assessments", "Microlearning", "Continuous Support"]', '[]', '2025-06-18 09:33:04.457+00', '2025-06-18 09:33:04.457+00');
